    "privacy.001.privacy_policy_clodia_in": "Privacy Policy — Clodia International FZE",
    "privacy.002.privacy_policy_for_clodi": "Privacy Policy for Clodia International FZE.",
    "privacy.003.clodia_international_fze": "Clodia International FZE is committed to protecting the privacy of visitors to this website. This Privacy Policy explains what data we collect, why, and how we handle it.",
    "privacy.004.1_controller": "1. Controller",
    "privacy.005.clodia_international_fze": "Clodia International FZE<br/>\n      of Saif Lounge, P.O. Box 122140, Sharjah, UAE<br/>\n      Email: <a href=\"mailto:info@clodia-int.com\" style=\"color:var(--copper)\">info@clodia-int.com</a>",
    "privacy.006.2_data_collected": "2. Data collected",
    "privacy.007.contact_forms_collect_na": "Contact forms collect name, email address, phone number (optional), and the content of the message. This data is used solely to respond to the enquiry. Standard server logs may record IP address, browser type, referring page, and timestamp.",
    "privacy.008.3_purpose_and_legal_basi": "3. Purpose and legal basis",
    "privacy.009.enquiry_data_is_processe": "Enquiry data is processed on the basis of consent (the form's consent box) and to take steps at the user's request before entering into a contract. Server log data is processed on the basis of legitimate interest in operating a secure, functional website.",
    "privacy.010.4_retention": "4. Retention",
    "privacy.011.enquiry_data_is_retained": "Enquiry data is retained for as long as necessary to handle the request, typically up to twenty-four months. Server logs are retained for up to thirty days. Deletion may be requested at any time.",
    "privacy.012.5_rights": "5. Rights",
    "privacy.013.users_have_the_right_to": "Users have the right to access, correct, or delete their personal data, to restrict or object to processing, and to data portability. To exercise these rights, email <a href=\"mailto:info@clodia-int.com\" style=\"color:var(--copper)\">info@clodia-int.com</a>.",
    "privacy.014.6_third_party_services": "6. Third-party services",
    "privacy.015.this_site_is_hosted_on_n": "This site is hosted on Netlify (Netlify, Inc., USA). Form submissions are processed through Netlify Forms. Fonts are loaded from Google Fonts (Google LLC, USA). These providers process technical data (such as IP address) to deliver the service. We do not use advertising trackers or third-party analytics on this site.",
    "privacy.016.7_cookies": "7. Cookies",
    "privacy.017.this_site_does_not_set_t": "This site does not set tracking or advertising cookies. Only strictly necessary cookies, if any, for form functionality or security may be used. No consent banner is required because no non-essential cookies are set.",
    "privacy.018.8_international_transfer": "8. International transfers",
    "privacy.019.because_the_hosting_and": "Because the hosting and font providers operate servers in the United States, data submitted may be transferred to and stored outside the UAE. We rely on the providers' standard contractual protections for international data transfers.",
    "privacy.020.9_changes": "9. Changes",
    "privacy.021.this_policy_may_be_updat": "This policy may be updated. The current version is always available at this URL. Date of last revision: April 2026."
