    "imprint.001.imprint_clodia_internati": "Impressum — Clodia International FZE",
    "index.001.clodia_international_fze": "Clodia International FZE — Handel und Clearing in den VAE, Gold und Rohstoffe",
    "index.002.uae_trade_and_clearing_s": "Handels- und Clearing-Tochter der International Finance Corporation in den VAE, Miami. Gold, Edelmetalle und Rohstoffe werden unter einer dokumentierten Compliance-Architektur in die VAE importiert. Sharjah Airport Free Zone.",
    "index.003.clodia_international_fze": "Clodia International <em style=\"font-style:normal;color:var(--copper)\">FZE</em>",
