    "contact.005.registered_address_of_sa": "<strong>Gevestigd adres</strong><br/>\n          van Saif Lounge, P.O. Box 122140<br/>\n          Sharjah, Verenigde Arabische Emiraten<br/><br/>\n<strong>E-mail</strong><br/>\n<a href=\"mailto:info@clodia-int.com\" style=\"color:var(--copper)\">info@clodia-int.com</a><br/><br/>\n<strong>Telefoon</strong><br/>\n<a href=\"tel:+971559966777\" style=\"color:var(--copper)\">+971 55 9966777</a><br/><br/>\n<strong>Leveringen</strong><br/>\n          Sharjah Airport Free Zone<br/><br/>\n<strong>Uren</strong><br/>\n          Zondag tot donderdag, 09:00 tot 18:00 GST<br/><br/>\n<strong>Groep</strong><br/>\n          Een dochteronderneming van International Finance Corporation<br/>\n          848 Brickell Avenue, Penthouse 5, Miami FL 33131, USA",
