    "index.046.imprint": "<a href=\"/imprint.html\">פרסום</a>",
    "index.047.privacy_policy": "<a href=\"/privacy.html\">מדיניות פרטיות</a>",
    "index.048.2026_clodia_internation": "© <span data-year=\"\">2026</span> Clodia International FZE. כל הזכויות שמורות.",
    "index.049.sharjah_airport_free_zon": "Sharjah Airport Free Zone · UAE",
    "services.001.services_clodia_internat": "שירותים — Clodia International FZE",
    "services.002.gold_importation_and_exp": "ייבוא וייצוא זהב, מסחר במתכות יקרות, ייבוא סחורות, וייצוא מוצרים מוגמרים. פועל בהתאם לתקני OECD, DMCC, ותקני משרד הכלכלה של האמירויות.",
    "services.003.gold_precious_metals_and": "זהב, מתכות יקרות וסחורות מטופלים בדיוק מתועד.",
    "services.004.four_service_lines_one_i": "ארבע קווי שירות, יכולת אספקה משולבת אחת, פועלים תחת ארכיטקטורת הציות של International Finance Corporation, מיאמי.",
    "services.005.overview": "סקירה",
    "services.006.the_operating_premise": "הנחת הפעולה.",
    "services.007.clodia_international_fze": "Clodia International FZE היא חברת הבת המסחרית והסליקה של International Finance Corporation באמירויות. מודל הפעולה מתבסס על הנחה אחת: במסחר חוצה גבולות של זהב וסחורות, העסקה נעשית בנקודת המקור ונפתרת בנקודת הציות. ארבעת קווי השירות שלנו מכסים כל שלב של הקשת, מתיעוד המקור ועד למסירת היעד, תחת קובץ ביקורת מאוחד.",
    "services.008.01_gold_importation_and": "<span class=\"num\">01</span> ייבוא וייצוא זהב",
    "services.009.clodia_sources_and_impor": "Clodia מקורות ומייבאת זהב לאמירויות באמצעות מסגרת המותאמת לתקנות בדיקת נאותות של משרד הכלכלה של האמירויות (צו משרדי 68 של 2024) וההנחיה של OECD לחמישה שלבים.",
    "services.010.gold_is_acquired_from_ce": "זהב נרכש ממכרות מוסמכות דרך ספקים שנבדקו בהתאם לתקן KYC של הקבוצה. מדינות המקור מדורגות: Tier 1 לשיפוטים בסיכון נמוך, Tier 2 לסיכון בינוני, Tier 3 לאזורים מושפעים וקונפליקטיים. מטענים של Tier 2 ו‑Tier 3 דורשים דוח וידוא עצמאי של OECD שלב‑5 שהונפק ב‑90 הימים הקודמים. ללא דוח זה, המשלוח אינו זז.",
    "services.011.pricing_follows_the_lond": "התמחור מתבסס על מדד של London Bullion Market Association בניכוי הנחה קבועה, מחושב על תכולת זהב טהור של 99.99% ביום ניתוח הזיקוק. זהב מתחת ל‑99.99% טוהר משולם על פי תכולת הזהב הטהור בפועל, שנקבעת על ידי זיקוק מוסמך Good Delivery של DMCC בדובאי. גודל המשלוח הסטנדרטי הוא מאה קילוגרם לחודש במשך תקופה של שנים‑עשר חודשים, עם אפשרות להרחבה בהסכמה.",
    "services.012.delivery_is_in_dore_bars": "המשלוח הוא בברי דור של 10 עד 12.5 קילוגרם, מינימום 92% Au, יצוק באתר המכרה, אטום ריק, וארוז בקופסאות בוליון חסינות חבלה מאושרות על ידי האו״ם. לכל בר מצורף קוד המכרה, מספר בר, משקל גולמי ותאריך יציקה. קוד QR על כל קופסה מקשר לקובץ השרשרת הדיגיטלית של המשמורת.",
    "services.013.counterparties_without_p": "צדדים ללא היסטוריית עסקאות קודמת עם הקבוצה נכנסים דרך פרוטוקול ניסיון: פחות מחמישה עשר קילוגרם של זהב טהור, תשלום במזומן, תיעוד ייצוא מלא, תשלום בדובאי על ניתוח מאושר. הניסיון הוא מבחן ציות ותפעול בקנה מידה מצומצם. הצלחה פותחת את המסגרת הסטנדרטית.",
    "services.014.the_seller_opens_an_acco": "המוכר פותח חשבון ב‑IFB International Finance Bank, ערוץ הבנקאות של הקבוצה. הקונה מפקיד את מחיר הרכישה בחשבון IFB של המוכר, שם הכספים חסומים עד שהזיקוק בדובאי מנפיק את ניתוח האסיי המאושר. השחרור מתבצע כנגד תכולת הזהב הטהור המאושרת, בניכוי ההפחתות המפורטות בהסכם הקנייה והמכירה. ההסדר יכול להיות במזומן בדובאי, במטבע אחר בהעברה בנקאית, או מועבר לבנק של צד שלישי לפי הוראת המוכר בכתב.",
    "services.015.transport_from_origin_ai": "הובלה משדה התעופה המקורי לדובאי מתבצעת באמצעות שירות Secure Vault של Emirates SkyCargo או שירות שווה ערך, מבוטח ב‑110% משווי LME דרך Lloyd's, תביעות משולמות בדובאי. הגשת מידע מקדים על המטען נעשית למכס דובאי 24 שעות לפני כל טיסה, בהתאם להודעת מכס 7/2023. הפינוי מטופל על ידי Clodia בנמל הבינלאומי של דובאי, והמטען מועבר ישירות לזיקוק המיועד בליווי משוריין.",
    "services.016.each_shipment_travels_wi": "כל משלוח נוסע עם סט המסמכים המלא: תעודת מקור, תעודת בעלות, חשבוניות מסחריות ומכס, הצהרת זהב ללא קונפליקט, שטר מטען, רשימת אריזה, קבלות תשלום מס ומכס, תעודת אסיי, רישיון ייצוא, שטר אוויר, תעודת ביטוח, הרשאה למכור ל‑IFB Holdings LLC כישות הקונה האמריקאית של הקבוצה, פינוי מכס של האמירויות, רישום MoE DNFBP, שאלון הערכה עצמית של MoEC לגבי מקור אחראי, אישור מקדים של הזיקוק, ומספר הגשת ACI. הפרת ברית הסנקציות מהווה אירוע ברירת מחדל.",
    "services.017.02_precious_metals_tradi": "<span class=\"num\">02</span> מסחר במתכות יקרות",
    "services.018.beyond_gold_clodia_trade": "מעבר לזהב, Clodia סוחרת כסף, פלטינה ופאלדיום עבור צדדים תעשייתיים, משקיעים ויצרנים.",
    "services.019.physical_supply_across_t": "אספקה פיזית של ארבע המתכות היקרות, במקור לפי אותו תקן ציות המוחל על זהב, עם מסגרת CAHRA מדורגת ויישור OECD המורחב על פני המוצרים.",
    "services.020.precious_metals_pricing": "תמחור המתכות היוקרתיות מגיב למדיניות מוניטרית, אירועים גיאופוליטיים, ביקוש תעשייתי ותנועת מטבע. אנו מספקים לצדדים מידע מסחרי רלוונטי, לא ניתוח שוק.",
    "services.021.hedging_structures_and_f": "מבני גידור וכלים פיננסיים המגנים על עמדות מפני תנועות מחיר שליליות, מובנים בתיאום עם תשתית הפיננסית של הקבוצה.",
    "services.022.suppliers_are_required_t": "ספקים נדרשים להציג פרקטיקות כרייה אחראיות בנקודת המקור. מתכות הקשורות לקונפליקט מוסרות בשלב סינון הספק, לא בשלבים מאוחרים יותר בשרשרת.",
